"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["41442"],{24486(i){i.exports=JSON.parse('{"tag":{"label":"microservices","permalink":"/sysanalyst-kb.github.io/docs/tags/microservices","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":6,"items":[{"id":"integration/api-gateway","title":"API Gateway pattern","description":"API Gateway \u2014 \u044D\u0442\u043E \u0435\u0434\u0438\u043D\u0430\u044F \u0442\u043E\u0447\u043A\u0430 \u0432\u0445\u043E\u0434\u0430 \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u0432 (web, mobile, third-party), \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0437\u0430\u043F\u0440\u043E\u0441\u044B \u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043C, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u043A\u0440\u043E\u0441\u0441-\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0438 \u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-gateway"},{"id":"architecture/cqrs","title":"CQRS \u2014 Command Query Responsibility Segregation","description":"CQRS \u2014 \u043F\u0430\u0442\u0442\u0435\u0440\u043D, \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0439 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u0447\u0442\u0435\u043D\u0438\u044F (Query) \u0438 \u0437\u0430\u043F\u0438\u0441\u0438 (Command). \u0412 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0435 \u043E\u0434\u043D\u0430 \u043C\u043E\u0434\u0435\u043B\u044C \u0434\u0430\u043D\u043D\u044B\u0445 \u0438 \u0434\u043B\u044F \u0447\u0442\u0435\u043D\u0438\u044F, \u0438 \u0434\u043B\u044F \u0437\u0430\u043F\u0438\u0441\u0438. CQRS \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u0440\u0430\u0437\u043D\u044B\u0435 \u043C\u043E\u0434\u0435\u043B\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/cqrs"},{"id":"architecture/tracing","title":"Distributed Tracing \u2014 \u0442\u0440\u0430\u0441\u0441\u0438\u0440\u043E\u0432\u043A\u0430 \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432 \u0432 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u0430\u0445","description":"Distributed tracing (\u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u0430\u044F \u0442\u0440\u0430\u0441\u0441\u0438\u0440\u043E\u0432\u043A\u0430) \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u043F\u0440\u043E\u0441\u043B\u0435\u0434\u0438\u0442\u044C \u043F\u0443\u0442\u044C \u0437\u0430\u043F\u0440\u043E\u0441\u0430 \u0447\u0435\u0440\u0435\u0437 \u0432\u0441\u0435 \u0441\u0435\u0440\u0432\u0438\u0441\u044B \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u044B. \u041A\u043E\u0433\u0434\u0430 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C \u043D\u0430\u0436\u0438\u043C\u0430\u0435\u0442 \u043A\u043D\u043E\u043F\u043A\u0443 \xab\u041E\u0444\u043E\u0440\u043C\u0438\u0442\u044C \u0437\u0430\u043A\u0430\u0437\xbb, \u0437\u0430\u043F\u0440\u043E\u0441 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u0440\u0435\u0437 5\u201310 \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432. Tracing \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0433\u0434\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u0430 \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0430 \u0438\u043B\u0438 \u043E\u0448\u0438\u0431\u043A\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442, \u043A\u0430\u043A\u0438\u0435 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u0442\u0440\u0435\u0439\u0441\u0438\u0442\u044C \u0438 \u043A\u0430\u043A\u0438\u0435 \u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435 \u043F\u0435\u0440\u0435\u0434\u0430\u0432\u0430\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/docs/architecture/tracing"},{"id":"architecture/resilience-patterns","title":"Resilience patterns \u2014 circuit breaker, retry, bulkhead, rate limiting","description":"Resilience patterns (\u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B \u043E\u0442\u043A\u0430\u0437\u043E\u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u0438) \u2014 \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0439 \u043A \u0441\u0431\u043E\u044F\u043C. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442, \u043A\u0430\u043A \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0434\u043E\u043B\u0436\u043D\u0430 \u0432\u0435\u0441\u0442\u0438 \u0441\u0435\u0431\u044F \u043F\u0440\u0438 \u043E\u0448\u0438\u0431\u043A\u0430\u0445: \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u0442\u044C \u0437\u0430\u043F\u0440\u043E\u0441\u044B \u0438\u043B\u0438 \u043D\u0435\u0442, \u043A\u0430\u043A \u0434\u043E\u043B\u0433\u043E \u0436\u0434\u0430\u0442\u044C, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u0442\u044C \u043F\u0440\u0438 \u043F\u0440\u0435\u0432\u044B\u0448\u0435\u043D\u0438\u0438 \u043B\u0438\u043C\u0438\u0442\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/architecture/resilience-patterns"},{"id":"architecture/microservices-patterns","title":"\u041C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u0431\u0430\u0437\u043E\u0432\u044B\u0435 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B","description":"\u041F\u0435\u0440\u0435\u0445\u043E\u0434 \u043D\u0430 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u044D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u044E, \u0430 \u043F\u0440\u043E \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044E. \u041A\u0430\u0436\u0434\u044B\u0439 \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u044B \u0440\u0435\u0448\u0430\u0435\u0442 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u0443\u044E \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0443, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u043F\u0440\u0438 \u0434\u0435\u043B\u0435\u043D\u0438\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043D\u0430 \u0447\u0430\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/microservices-patterns"},{"id":"architecture/monolith-vs-microservices","title":"\u041C\u043E\u043D\u043E\u043B\u0438\u0442 vs \u041C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B","description":"\u0421\u043F\u043E\u0440 \xab\u043C\u043E\u043D\u043E\u043B\u0438\u0442 \u0438\u043B\u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B\xbb \u0434\u0430\u0432\u043D\u043E \u043F\u043E\u0442\u0435\u0440\u044F\u043B \u0441\u043C\u044B\u0441\u043B. \u042D\u0442\u043E \u043D\u0435 \u0432\u043E\u043F\u0440\u043E\u0441 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0438, \u0430 \u0432\u043E\u043F\u0440\u043E\u0441 \u043A\u043E\u043C\u043F\u0440\u043E\u043C\u0438\u0441\u0441\u0430. \u041E\u0431\u0430 \u043F\u043E\u0434\u0445\u043E\u0434\u0430 \u0438\u043C\u0435\u044E\u0442 \u0446\u0435\u043D\u0443, \u0438 \u0432\u044B\u0431\u043E\u0440 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430: \u0441\u0442\u0430\u0434\u0438\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430, \u0440\u0430\u0437\u043C\u0435\u0440\u0430 \u043A\u043E\u043C\u0430\u043D\u0434\u044B, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0439 \u043A \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044E.","permalink":"/sysanalyst-kb.github.io/docs/architecture/monolith-vs-microservices"}],"unlisted":false}}')}}]);